import Fab from '@mui/material/Fab';
import Menu from '@mui/material/Menu';
import MenuItem from '@mui/material/MenuItem';
import ListItemIcon from '@mui/material/ListItemIcon';
import ListItemText from '@mui/material/ListItemText';
import Button from '@mui/material/Button';
import FilterListIcon from '@mui/icons-material/FilterList';
import CheckIcon from '@mui/icons-material/Check';
import KeyboardArrowDownIcon from '@mui/icons-material/KeyboardArrowDown';
import { useCallback, useMemo, useState, useRef, useEffect } from 'react';

import useAuth from '@/context/hooks/useAuth';
import useMessages from '@/context/hooks/useMessages';
import useSendSettings from '@/hooks/useSendSettings';
import { useTranslation } from 'react-i18next';
import Message from './Message';
import MessageSkeleton from './MessageSkeleton';
import './styles.css';
import { MessageType as MsgType } from '@/types/Message';

interface MessageListProps {
  room: string;
  isTransparent?: boolean;
  currentGameBoardSize?: number;
}

export default function MessageList({
  room,
  isTransparent,
  currentGameBoardSize = 40,
}: MessageListProps): JSX.Element {
  const containerRef = useRef<HTMLDivElement>(null);
  const { user } = useAuth();
  const { messages, isLoading } = useMessages();
  useSendSettings(user, messages, isLoading);

  const [currentTab, setCurrentTab] = useState<number>(0);
  const [filterAnchor, setFilterAnchor] = useState<null | HTMLElement>(null);
  const [showJumpToLatest, setShowJumpToLatest] = useState(false);
  const { t } = useTranslation();

  // Memoize filtered messages directly to avoid creating a new function on each render
  const updatedMessages = useMemo(() => {
    return messages.filter((m) => {
      if (currentTab === 1) return ['settings', 'room'].includes(m.type as MsgType);
      if (currentTab === 2) return ['chat', 'media'].includes(m.type as MsgType);
      if (currentTab === 3) return m.type === 'actions';
      return true; // currentTab === 0 (all messages)
    });
  }, [messages, currentTab]);

  const isAtBottom = useCallback((element: HTMLDivElement | null) => {
    if (!element) return true;

    return element.scrollTop + element.clientHeight >= element.scrollHeight - 1;
  }, []);

  const scrollToLatest = useCallback(() => {
    if (!containerRef.current) return;

    containerRef.current.scrollTop = containerRef.current.scrollHeight;
    setShowJumpToLatest(false);
  }, []);

  // Scroll to bottom when new messages are added and the reader is already near the bottom
  const lastRenderedMessageIdRef = useRef<string | null>(null);
  const followLatestRef = useRef(true);

  useEffect(() => {
    const latestMessage = updatedMessages[updatedMessages.length - 1];
    const latestMessageId = latestMessage?.id || null;

    if (!latestMessageId) {
      return;
    }

    // Always land on the latest message the first time the list is populated.
    if (!lastRenderedMessageIdRef.current) {
      lastRenderedMessageIdRef.current = latestMessageId;
      scrollToLatest();
      return;
    }

    // Only scroll if this is actually a new message.
    if (latestMessageId !== lastRenderedMessageIdRef.current) {
      lastRenderedMessageIdRef.current = latestMessageId;

      if (followLatestRef.current) {
        scrollToLatest();
      } else {
        setShowJumpToLatest(true);
      }
    }
  }, [scrollToLatest, updatedMessages]);

  const handleScroll = useCallback(() => {
    const atBottom = isAtBottom(containerRef.current);
    followLatestRef.current = atBottom;

    if (atBottom) {
      setShowJumpToLatest(false);
    }
  }, [isAtBottom]);

  const handleFilterClick = useCallback((event: React.MouseEvent<HTMLElement>) => {
    setFilterAnchor(event.currentTarget);
  }, []);

  const handleFilterClose = useCallback(() => {
    setFilterAnchor(null);
  }, []);

  const handleFilterSelect = useCallback((filterIndex: number) => {
    setCurrentTab(filterIndex);
    setFilterAnchor(null);
  }, []);

  const filterOptions = [
    { label: t('all'), value: 0 },
    { label: t('setting'), value: 1 },
    { label: t('chat'), value: 2 },
    { label: t('actions'), value: 3 },
  ];

  return (
    <div className="message-list-container">
      <div
        className="message-list-scroll transparent-scrollbar"
        ref={containerRef}
        onScroll={handleScroll}
      >
        <div className="message-list-scroll-content">
          <ul className="message-list">
            {isLoading && updatedMessages.length === 0 ? (
              <MessageSkeleton count={5} />
            ) : (
              updatedMessages.map((x) => {
                // Memoize isOwnMessage calculation outside render
                const isOwnMessage = x.uid === user?.uid;
                return (
                  <Message
                    key={x.id}
                    message={x}
                    isOwnMessage={isOwnMessage}
                    isTransparent={isTransparent}
                    currentGameBoardSize={currentGameBoardSize}
                    room={room}
                  />
                );
              })
            )}
          </ul>
        </div>
      </div>

      {showJumpToLatest && (
        <div className="message-jump-status" role="status" aria-live="polite">
          {t('newMessages', 'New messages')}
        </div>
      )}

      {showJumpToLatest && (
        <Button
          className="message-jump-to-latest"
          variant="contained"
          size="small"
          onClick={scrollToLatest}
          startIcon={<KeyboardArrowDownIcon />}
        >
          {t('newMessages', 'New messages')}
        </Button>
      )}

      {/* Filter Button Overlay */}
      <div className="message-filter-header">
        <Fab
          size="medium"
          color="primary"
          aria-label="filter messages"
          onClick={handleFilterClick}
          className="message-filter-fab"
          sx={{ transform: 'scale(0.8)' }}
        >
          <FilterListIcon />
        </Fab>
      </div>

      {/* Filter Menu */}
      <Menu
        anchorEl={filterAnchor}
        open={Boolean(filterAnchor)}
        onClose={handleFilterClose}
        anchorOrigin={{
          vertical: 'bottom',
          horizontal: 'right',
        }}
        transformOrigin={{
          vertical: 'top',
          horizontal: 'right',
        }}
        slotProps={{
          paper: {
            style: {
              maxHeight: '200px',
              minWidth: '120px',
            },
          },
        }}
      >
        {filterOptions.map((option) => (
          <MenuItem
            key={option.value}
            onClick={() => handleFilterSelect(option.value)}
            selected={currentTab === option.value}
          >
            <ListItemIcon>{currentTab === option.value && <CheckIcon />}</ListItemIcon>
            <ListItemText primary={option.label} />
          </MenuItem>
        ))}
      </Menu>
    </div>
  );
}
